import { useEffect, useMemo, useRef } from 'react'
import type { RefObject } from 'react'
import { autoUpdate } from '@floating-ui/dom'
import {
  debounce,
  getScrollParent,
  clearTimeoutRef,
  parseDataTooltipIdSelector,
  resolveDataTooltipAnchor,
} from '../../utils'
import type {
  AnchorCloseEvents,
  AnchorOpenEvents,
  GlobalCloseEvents,
  IPosition,
} from './TooltipTypes'
import { addDelegatedEventListener } from './event-delegation'

const useTooltipEvents = ({
  activeAnchor,
  anchorElements,
  anchorSelector,
  clickable,
  closeEvents,
  delayHide,
  delayShow,
  disableTooltip,
  float,
  globalCloseEvents,
  handleHideTooltipDelayed,
  handleShow,
  handleShowTooltipDelayed,
  handleTooltipPosition,
  hoveringTooltip,
  imperativeModeOnly,
  lastFloatPosition,
  openEvents,
  openOnClick,
  setActiveAnchor,
  show,
  tooltipHideDelayTimerRef,
  tooltipRef,
  tooltipShowDelayTimerRef,
  updateTooltipPosition,
}: {
  activeAnchor: HTMLElement | null
  anchorElements: HTMLElement[]
  anchorSelector: string
  clickable: boolean
  closeEvents?: AnchorCloseEvents
  delayHide: number
  delayShow: number
  disableTooltip?: (anchorRef: HTMLElement | null) => boolean
  float: boolean
  globalCloseEvents?: GlobalCloseEvents
  handleHideTooltipDelayed: (delay?: number) => void
  handleShow: (value: boolean) => void
  handleShowTooltipDelayed: (delay?: number) => void
  handleTooltipPosition: ({ x, y }: IPosition) => void
  hoveringTooltip: RefObject<boolean>
  imperativeModeOnly?: boolean
  lastFloatPosition: RefObject<IPosition | null>
  openEvents?: AnchorOpenEvents
  openOnClick: boolean
  setActiveAnchor: (anchor: HTMLElement | null) => void
  show: boolean
  tooltipHideDelayTimerRef: RefObject<NodeJS.Timeout | null>
  tooltipRef: RefObject<HTMLElement | null>
  tooltipShowDelayTimerRef: RefObject<NodeJS.Timeout | null>
  updateTooltipPosition: () => void
}) => {
  // Ref-stable debounced handlers — avoids recreating debounce instances on every effect run
  // eslint-disable-next-line @typescript-eslint/no-unused-vars
  const debouncedShowRef = useRef(debounce((_anchor: HTMLElement | null) => {}, 50, true))
  const debouncedHideRef = useRef(debounce(() => {}, 50, true))

  // Cache scroll parents — only recompute when the element actually changes
  const anchorScrollParentRef = useRef<Element | null>(null)
  const tooltipScrollParentRef = useRef<Element | null>(null)
  const prevAnchorRef = useRef<HTMLElement | null>(null)
  const prevTooltipRef = useRef<HTMLElement | null>(null)

  if (activeAnchor !== prevAnchorRef.current) {
    prevAnchorRef.current = activeAnchor
    anchorScrollParentRef.current = getScrollParent(activeAnchor)
  }
  const currentTooltipEl = tooltipRef.current
  if (currentTooltipEl !== prevTooltipRef.current) {
    prevTooltipRef.current = currentTooltipEl
    tooltipScrollParentRef.current = getScrollParent(currentTooltipEl)
  }

  // Memoize event config objects — only rebuild when the relevant props change
  const hasClickEvent =
    openOnClick || openEvents?.click || openEvents?.dblclick || openEvents?.mousedown
  const actualOpenEvents: AnchorOpenEvents = useMemo(() => {
    const events: AnchorOpenEvents = openEvents
      ? { ...openEvents }
      : {
          mouseenter: true,
          focus: true,
          click: false,
          dblclick: false,
          mousedown: false,
        }
    if (!openEvents && openOnClick) {
      Object.assign(events, {
        mouseenter: false,
        focus: false,
        click: true,
      })
    }
    if (imperativeModeOnly) {
      Object.assign(events, {
        mouseenter: false,
        focus: false,
        click: false,
        dblclick: false,
        mousedown: false,
      })
    }
    return events
  }, [openEvents, openOnClick, imperativeModeOnly])

  const actualCloseEvents: AnchorCloseEvents = useMemo(() => {
    const events: AnchorCloseEvents = closeEvents
      ? { ...closeEvents }
      : {
          mouseleave: true,
          blur: true,
          click: false,
          dblclick: false,
          mouseup: false,
        }
    if (!closeEvents && openOnClick) {
      Object.assign(events, {
        mouseleave: false,
        blur: false,
      })
    }
    if (imperativeModeOnly) {
      Object.assign(events, {
        mouseleave: false,
        blur: false,
        click: false,
        dblclick: false,
        mouseup: false,
      })
    }
    return events
  }, [closeEvents, openOnClick, imperativeModeOnly])

  const actualGlobalCloseEvents: GlobalCloseEvents = useMemo(() => {
    const events: GlobalCloseEvents = globalCloseEvents
      ? { ...globalCloseEvents }
      : {
          escape: false,
          scroll: false,
          resize: false,
          clickOutsideAnchor: hasClickEvent || false,
        }
    if (imperativeModeOnly) {
      Object.assign(events, {
        escape: false,
        scroll: false,
        resize: false,
        clickOutsideAnchor: false,
      })
    }
    return events
  }, [globalCloseEvents, hasClickEvent, imperativeModeOnly])

  // --- Refs for values read inside event handlers (avoids effect deps) ---
  const activeAnchorRef = useRef(activeAnchor)
  activeAnchorRef.current = activeAnchor
  const showRef = useRef(show)
  showRef.current = show
  const anchorElementsRef = useRef(anchorElements)
  anchorElementsRef.current = anchorElements
  const handleShowRef = useRef(handleShow)
  handleShowRef.current = handleShow
  const handleTooltipPositionRef = useRef(handleTooltipPosition)
  handleTooltipPositionRef.current = handleTooltipPosition
  const updateTooltipPositionRef = useRef(updateTooltipPosition)
  updateTooltipPositionRef.current = updateTooltipPosition

  // --- Handler refs (updated every render, read via ref indirection in effects) ---
  const resolveAnchorElementRef = useRef<(target: EventTarget | null) => HTMLElement | null>(
    () => null,
  )
  const handleShowTooltipRef = useRef<(anchor: HTMLElement | null) => void>(() => {})
  const handleHideTooltipRef = useRef<() => void>(() => {})

  const dataTooltipId = anchorSelector ? parseDataTooltipIdSelector(anchorSelector) : null

  resolveAnchorElementRef.current = (target: EventTarget | null) => {
    const targetElement = target as HTMLElement | null

    if (!targetElement?.isConnected) {
      return null
    }

    if (dataTooltipId) {
      const matchedAnchor = resolveDataTooltipAnchor(targetElement, dataTooltipId)

      if (matchedAnchor && !disableTooltip?.(matchedAnchor)) {
        return matchedAnchor
      }
    } else if (anchorSelector) {
      try {
        const matchedAnchor =
          (targetElement.matches(anchorSelector)
            ? targetElement
            : targetElement.closest(anchorSelector)) ?? null

        if (matchedAnchor && !disableTooltip?.(matchedAnchor as HTMLElement)) {
          return matchedAnchor as HTMLElement
        }
      } catch {
        return null
      }
    }

    return (
      anchorElementsRef.current.find(
        (anchor) => anchor === targetElement || anchor.contains(targetElement),
      ) ?? null
    )
  }

  handleShowTooltipRef.current = (anchor: HTMLElement | null) => {
    if (!anchor) {
      return
    }
    if (!anchor.isConnected) {
      setActiveAnchor(null)
      return
    }
    if (disableTooltip?.(anchor)) {
      return
    }
    if (delayShow) {
      handleShowTooltipDelayed()
    } else {
      handleShow(true)
    }
    if (delayShow && activeAnchorRef.current && anchor !== activeAnchorRef.current) {
      // Moving to a different anchor while one is already active — defer the anchor
      // switch until the show delay fires to prevent content/position from updating
      // before visibility transitions complete.
      if (tooltipShowDelayTimerRef.current) {
        clearTimeout(tooltipShowDelayTimerRef.current)
      }
      tooltipShowDelayTimerRef.current = setTimeout(() => {
        setActiveAnchor(anchor)
        handleShow(true)
      }, delayShow)
    } else {
      setActiveAnchor(anchor)
    }

    if (tooltipHideDelayTimerRef.current) {
      clearTimeout(tooltipHideDelayTimerRef.current)
    }
  }

  handleHideTooltipRef.current = () => {
    if (clickable) {
      handleHideTooltipDelayed(delayHide || 100)
    } else if (delayHide) {
      handleHideTooltipDelayed()
    } else {
      handleShow(false)
    }

    if (tooltipShowDelayTimerRef.current) {
      clearTimeout(tooltipShowDelayTimerRef.current)
    }
  }

import React, {
  useEffect,
  useMemo,
  useState,
  useRef,
  useCallback,
  useImperativeHandle,
  memo,
} from 'react'
import { createPortal } from 'react-dom'
import clsx from 'clsx'
import {
  useIsomorphicLayoutEffect,
  computeTooltipPosition,
  cssTimeToMs,
  clearTimeoutRef,
} from '../../utils'
import type { IComputedPosition } from '../../utils'
import coreStyles from './core-styles.module.css'
import styles from './styles.module.css'
import useTooltipAnchors from './use-tooltip-anchors'
import useTooltipEvents from './use-tooltip-events'
import type { IPosition, ITooltip, TooltipImperativeOpenOptions } from './TooltipTypes'

// Shared across all tooltip instances — the CSS variable is on :root and never changes per-instance
let globalTransitionShowDelay: number | null = null

const Tooltip = ({
  // props
  forwardRef,
  id,
  className,
  classNameArrow,
  variant = 'dark',
  portalRoot,
  anchorSelect,
  place = 'top',
  offset = 10,
  openOnClick = false,
  positionStrategy = 'absolute',
  middlewares,
  wrapper: WrapperElement,
  delayShow = 0,
  delayHide = 0,
  autoClose,
  float = false,
  hidden = false,
  noArrow = false,
  clickable = false,
  openEvents,
  closeEvents,
  globalCloseEvents,
  imperativeModeOnly,
  style: externalStyles,
  position,
  afterShow,
  afterHide,
  disableTooltip,
  // props handled by controller
  content,
  contentWrapperRef,
  isOpen,
  defaultIsOpen = false,
  setIsOpen,
  previousActiveAnchor,
  activeAnchor,
  setActiveAnchor,
  border,
  opacity,
  arrowColor,
  arrowSize = 8,
  role = 'tooltip',
}: ITooltip) => {
  const tooltipRef = useRef<HTMLElement>(null)
  const tooltipArrowRef = useRef<HTMLElement>(null)
  const tooltipShowDelayTimerRef = useRef<NodeJS.Timeout | null>(null)
  const tooltipHideDelayTimerRef = useRef<NodeJS.Timeout | null>(null)
  const tooltipAutoCloseTimerRef = useRef<NodeJS.Timeout | null>(null)
  const missedTransitionTimerRef = useRef<NodeJS.Timeout | null>(null)
  const [computedPosition, setComputedPosition] = useState<IComputedPosition>({
    tooltipStyles: {},
    tooltipArrowStyles: {},
    place,
  })
  const [show, setShow] = useState(false)
  const [rendered, setRendered] = useState(false)
  const [imperativeOptions, setImperativeOptions] = useState<TooltipImperativeOpenOptions | null>(
    null,
  )
  const wasShowing = useRef(false)
  const lastFloatPosition = useRef<IPosition | null>(null)
  const hoveringTooltip = useRef(false)
  const mounted = useRef(false)
  const virtualElementRef = useRef({
    getBoundingClientRect: () => ({
      x: 0,
      y: 0,
      width: 0,
      height: 0,
      top: 0,
      left: 0,
      right: 0,
      bottom: 0,
    }),
  })

  /**
   * useLayoutEffect runs before useEffect,
   * but should be used carefully because of caveats
   * https://beta.reactjs.org/reference/react/useLayoutEffect#caveats
   */
  useIsomorphicLayoutEffect(() => {
    mounted.current = true
    return () => {
      mounted.current = false
    }
  }, [])

  const handleShow = useCallback(
    (value: boolean) => {
      if (!mounted.current) {
        return
      }
      if (value) {
        setRendered(true)
      }
      /**
       * wait for the component to render and calculate position
       * before actually showing
       */
      setTimeout(() => {
        if (!mounted.current) {
          return
        }
        setIsOpen?.(value)
        if (isOpen === undefined) {
          setShow(value)
        }
      }, 10)
    },
    [isOpen, setIsOpen],
  )

  /**
   * Add aria-describedby to activeAnchor when tooltip is active
   */
  useEffect(() => {
    if (!id) return

    function getAriaDescribedBy(element: HTMLElement | null) {
      return element?.getAttribute('aria-describedby')?.split(' ') || []
    }

    function removeAriaDescribedBy(element: HTMLElement | null) {
      const newDescribedBy = getAriaDescribedBy(element).filter((s) => s !== id)
      if (newDescribedBy.length) {
        element?.setAttribute('aria-describedby', newDescribedBy.join(' '))
      } else {
        element?.removeAttribute('aria-describedby')
      }
    }

    if (show) {
      removeAriaDescribedBy(previousActiveAnchor)
      const currentDescribedBy = getAriaDescribedBy(activeAnchor)
      const describedBy = [...new Set([...currentDescribedBy, id])].filter(Boolean).join(' ')
      activeAnchor?.setAttribute('aria-describedby', describedBy)
    } else {
      removeAriaDescribedBy(activeAnchor)
    }

    return () => {
      // cleanup aria-describedby when the tooltip is closed
      removeAriaDescribedBy(activeAnchor)
      removeAriaDescribedBy(previousActiveAnchor)
    }
  }, [activeAnchor, show, id, previousActiveAnchor])

  /**
   * this replicates the effect from `handleShow()`
   * when `isOpen` is changed from outside
   */
  useEffect(() => {
    if (isOpen === undefined) {
      return () => null
    }
    if (isOpen) {
      setRendered(true)
    }
    const timeout = setTimeout(() => {
      setShow(isOpen)
    }, 10)
    return () => {
      clearTimeout(timeout)
    }
  }, [isOpen])

  useEffect(() => {
    if (show === wasShowing.current) {
      return
    }
    clearTimeoutRef(missedTransitionTimerRef)
    wasShowing.current = show
    if (show) {
      afterShow?.()
    } else {
      /**
       * see `onTransitionEnd` on tooltip wrapper
       */
      if (globalTransitionShowDelay === null) {
        const style = getComputedStyle(document.body)
        globalTransitionShowDelay = cssTimeToMs(
          style.getPropertyValue('--rt-transition-show-delay'),
        )
      }
      const transitionShowDelay = globalTransitionShowDelay
      missedTransitionTimerRef.current = setTimeout(() => {
        /**
         * if the tooltip switches from `show === true` to `show === false` too fast
         * the transition never runs, so `onTransitionEnd` callback never gets fired
         */
        setRendered(false)
        setImperativeOptions(null)
        afterHide?.()
        // +25ms just to make sure `onTransitionEnd` (if it gets fired) has time to run
      }, transitionShowDelay + 25)
    }
  }, [afterHide, afterShow, show])

  useEffect(() => {
    clearTimeoutRef(tooltipAutoCloseTimerRef)

    if (!show || !autoClose || autoClose <= 0) {
      return () => {
        clearTimeoutRef(tooltipAutoCloseTimerRef)
      }
    }

    tooltipAutoCloseTimerRef.current = setTimeout(() => {
      handleShow(false)
    }, autoClose)

    return () => {
      clearTimeoutRef(tooltipAutoCloseTimerRef)
    }
  }, [activeAnchor, autoClose, handleShow, show])

  const handleComputedPosition = useCallback((newComputedPosition: IComputedPosition) => {
    if (!mounted.current) {
      return
    }
    setComputedPosition((oldComputedPosition) => {
      if (
        oldComputedPosition.place === newComputedPosition.place &&
        oldComputedPosition.tooltipStyles.left === newComputedPosition.tooltipStyles.left &&
        oldComputedPosition.tooltipStyles.top === newComputedPosition.tooltipStyles.top &&
        oldComputedPosition.tooltipStyles.border === newComputedPosition.tooltipStyles.border &&
        oldComputedPosition.tooltipArrowStyles.left ===
          newComputedPosition.tooltipArrowStyles.left &&
        oldComputedPosition.tooltipArrowStyles.top === newComputedPosition.tooltipArrowStyles.top &&
        oldComputedPosition.tooltipArrowStyles.right ===
          newComputedPosition.tooltipArrowStyles.right &&
        oldComputedPosition.tooltipArrowStyles.bottom ===
          newComputedPosition.tooltipArrowStyles.bottom &&
        oldComputedPosition.tooltipArrowStyles.borderBottom ===
          newComputedPosition.tooltipArrowStyles.borderBottom &&
        oldComputedPosition.tooltipArrowStyles.borderRight ===
          newComputedPosition.tooltipArrowStyles.borderRight
      ) {
        return oldComputedPosition
      }
      return newComputedPosition
    })
  }, [])

  const handleShowTooltipDelayed = useCallback(
    (delay = delayShow) => {
      if (tooltipShowDelayTimerRef.current) {
        clearTimeout(tooltipShowDelayTimerRef.current)
      }

      if (rendered) {
        // if the tooltip is already rendered, ignore delay
        handleShow(true)
        return
      }

      tooltipShowDelayTimerRef.current = setTimeout(() => {
        handleShow(true)
      }, delay)
    },
    [delayShow, handleShow, rendered],
  )

  const handleHideTooltipDelayed = useCallback(
    (delay = delayHide) => {
      if (tooltipHideDelayTimerRef.current) {
        clearTimeout(tooltipHideDelayTimerRef.current)
      }

      tooltipHideDelayTimerRef.current = setTimeout(() => {
        if (hoveringTooltip.current) {
          return
        }
        handleShow(false)
      }, delay)
    },
    [delayHide, handleShow],
  )

  const handleTooltipPosition = useCallback(
    ({ x, y }: IPosition) => {
      virtualElementRef.current.getBoundingClientRect = () => ({
        x,
        y,
        width: 0,
        height: 0,
        top: y,
        left: x,
        right: x,
        bottom: y,
      })
      computeTooltipPosition({
        place: imperativeOptions?.place ?? place,
        offset,
        elementReference: virtualElementRef.current as unknown as Element,
        tooltipReference: tooltipRef.current,
        tooltipArrowReference: tooltipArrowRef.current,
        strategy: positionStrategy,
        middlewares,
        border,
        arrowSize,
      }).then((computedStylesData) => {
        handleComputedPosition(computedStylesData)
      })
    },
    [
      imperativeOptions?.place,
      place,
      offset,

import React, { useState } from 'react'
import { render, screen, fireEvent, waitFor, act } from '@testing-library/react'
import '@testing-library/jest-dom'
import { autoUpdate } from '@floating-ui/dom'
import { TooltipController } from '../components/TooltipController'
import {
  advanceTimers,
  flushMicrotasks,
  flushPendingTimers,
  hoverAnchor,
  unhoverAnchor,
  waitForTooltip,
  waitForTooltipToStopShowing,
} from './test-utils'

jest.mock('@floating-ui/dom', () => {
  const originalModule = jest.requireActual('@floating-ui/dom')
  return {
    ...originalModule,
    autoUpdate: jest.fn().mockImplementation((reference, floating, update) => {
      if (update) update()
      return jest.fn()
    }),
  }
})

describe('tooltip interaction behavior', () => {
  beforeEach(() => {
    jest.useFakeTimers()
    jest.clearAllMocks()
  })

  afterEach(() => {
    flushPendingTimers()
    jest.useRealTimers()
  })

  const renderAndFlush = async (ui) => {
    let view
    await act(async () => {
      view = render(ui)
      await Promise.resolve()
    })
    return view
  }

  test('opens on click when click is the configured trigger', async () => {
    await renderAndFlush(
      <>
        <span data-tooltip-id="click-only-test">Hover Me</span>
        <TooltipController
          id="click-only-test"
          content="Click Only Test"
          openEvents={{ click: true }}
          closeEvents={{ click: true }}
        />
      </>,
    )

    const anchor = screen.getByText('Hover Me')

    hoverAnchor(anchor, 100)
    expect(document.getElementById('click-only-test')).not.toBeInTheDocument()

    fireEvent.click(anchor)
    await flushMicrotasks()
    const tooltip = await waitForTooltip('click-only-test')
    expect(tooltip).toHaveTextContent('Click Only Test')
  })

  test('stops showing after scroll and resize global close events', async () => {
    await renderAndFlush(
      <>
        <span data-tooltip-id="global-events-test">Hover Me</span>
        <TooltipController
          id="global-events-test"
          content="Global Events Test"
          globalCloseEvents={{ scroll: true, resize: true }}
        />
      </>,
    )

    const anchor = screen.getByText('Hover Me')

    hoverAnchor(anchor, 1000)
    await waitForTooltip('global-events-test')

    fireEvent.scroll(window)
    advanceTimers(100)
    await flushMicrotasks()
    await waitForTooltipToStopShowing('global-events-test')

    // Allow the tooltip to fully unmount before re-hovering
    advanceTimers(100)
    await flushMicrotasks()

    hoverAnchor(anchor, 1000)
    await flushMicrotasks()
    await waitForTooltip('global-events-test')

    fireEvent.resize(window)
    advanceTimers(100)
    await flushMicrotasks()
    await waitForTooltipToStopShowing('global-events-test')
  })

  test('keeps a clickable tooltip open while the pointer moves into it', async () => {
    await renderAndFlush(
      <>
        <span data-tooltip-id="clickable-test">Hover Me</span>
        <TooltipController
          id="clickable-test"
          content="Clickable Test"
          clickable
          globalCloseEvents={{ scroll: true, resize: true }}
        />
      </>,
    )

    const anchor = screen.getByText('Hover Me')

    hoverAnchor(anchor, 1000)
    const tooltip = await waitForTooltip('clickable-test')

    unhoverAnchor(anchor, 0)
    fireEvent.mouseEnter(tooltip)
    await flushMicrotasks()
    expect(screen.getByRole('tooltip')).toBeInTheDocument()

    fireEvent.mouseLeave(tooltip)
    await flushMicrotasks()
    await waitForTooltipToStopShowing('clickable-test')
  })

  test('keeps autoUpdate wired when an active anchor is removed', async () => {
    const RemovableTest = () => {
      const [showAnchor, setShowAnchor] = useState(true)

      return (
        <div>
          {showAnchor && <span data-tooltip-id="removable-test">Hover Me</span>}
          <button onClick={() => setShowAnchor(false)}>Remove Anchor</button>
          <TooltipController id="removable-test" content="Removable Test" />
        </div>
      )
    }

    await renderAndFlush(<RemovableTest />)

    const anchor = screen.getByText('Hover Me')
    hoverAnchor(anchor, 500)
    await waitForTooltip('removable-test')

    fireEvent.click(screen.getByText('Remove Anchor'))
    await flushMicrotasks()

    await waitFor(() => {
      expect(screen.queryByText('Hover Me')).not.toBeInTheDocument()
    })
    expect(autoUpdate).toHaveBeenCalled()
  })

  test('opens without emitting runtime errors', async () => {
    const consoleErrorSpy = jest.spyOn(console, 'error').mockImplementation(() => {})

    await renderAndFlush(
      <>
        <span data-tooltip-id="console-error-test">Hover Me</span>
        <TooltipController id="console-error-test" content="Console Error Test" />
      </>,
    )

    hoverAnchor(screen.getByText('Hover Me'), 500)
    await flushMicrotasks()

    expect(screen.getByText('Console Error Test')).toBeInTheDocument()
    consoleErrorSpy.mockRestore()
  })

  test('ignores missing pointermove events in float mode', () => {
    const originalAddEventListener = HTMLSpanElement.prototype.addEventListener
    const listenerRegistry = []

    const addEventListenerSpy = jest
      .spyOn(HTMLSpanElement.prototype, 'addEventListener')
      .mockImplementation(function mockAddEventListener(event, listener, options) {
        listenerRegistry.push({ target: this, event, listener })
        return originalAddEventListener.call(this, event, listener, options)
      })

    render(
      <>
        <span data-tooltip-id="float-guard-test">Hover Me</span>
        <TooltipController id="float-guard-test" content="Float Guard Test" float />
      </>,
    )

    const pointerMoveListener = listenerRegistry.find(
      ({ target, event }) => target.textContent === 'Hover Me' && event === 'pointermove',
    )?.listener

    expect(() => {
      act(() => {
        pointerMoveListener?.()
      })
    }).not.toThrow()

    addEventListenerSpy.mockRestore()
  })

  test('ignores missing open events before an anchor is resolved', () => {
    const originalAddEventListener = HTMLSpanElement.prototype.addEventListener
    const listenerRegistry = []

    const addEventListenerSpy = jest
      .spyOn(HTMLSpanElement.prototype, 'addEventListener')
      .mockImplementation(function mockAddEventListener(event, listener, options) {
        listenerRegistry.push({ target: this, event, listener })
        return originalAddEventListener.call(this, event, listener, options)
      })

    render(
      <>
        <span data-tooltip-id="missing-open-event-test">Hover Me</span>
        <TooltipController id="missing-open-event-test" content="Missing Open Event Test" />
      </>,
    )

    const mouseEnterListener = listenerRegistry.find(
      ({ target, event }) => target.textContent === 'Hover Me' && event === 'mouseenter',
    )?.listener

    expect(() => {
      act(() => {
        mouseEnterListener?.()
      })
      advanceTimers(60)
    }).not.toThrow()
    expect(document.getElementById('missing-open-event-test')).not.toBeInTheDocument()

    addEventListenerSpy.mockRestore()
  })

  test('ignores disconnected anchors during open handling', () => {
    const originalAddEventListener = window.EventTarget.prototype.addEventListener
    const listenerRegistry = []

    const addEventListenerSpy = jest
      .spyOn(window.EventTarget.prototype, 'addEventListener')
